{"command": "cd /app/data/auto-opt/utils/llvm-105632 && python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/Utils/SimplifyCFG.cpp 4789 4804 \
'  // Determine the set of values mapping to the non-default destination.
  // We need exactly two distinct destinations.
  BasicBlock *NonDefaultDest = nullptr;
  int Bitmask = 0; // bit 0 = -1, bit 1 = 0, bit 2 = 1

  auto addDest = [&](BasicBlock *Dest, int Bit) {
    if (Dest == DefaultDest)
      return;
    if (!NonDefaultDest) {
      NonDefaultDest = Dest;
      Bitmask = Bit;
    } else if (Dest == NonDefaultDest) {
      Bitmask |= Bit;
    } else {
      // More than two destinations.
      return;
    }
  };

  addDest(DestForMinusOne, 1);
  addDest(DestForZero, 2);
  addDest(DestForOne, 4);

  if (!NonDefaultDest || Bitmask == 7)
    return false;

  // Build the icmp condition. Bitmask tells us which values go to NonDefaultDest.
  CmpInst::Predicate Pred;
  if (Bitmask == 4) // Only value 1 (a > b)
    Pred = cast<CmpIntrinsic>(II)->getGTPredicate();
  else if (Bitmask == 1) // Only value -1 (a < b)
    Pred = cast<CmpIntrinsic>(II)->getLTPredicate();
  else if (Bitmask == 2) // Only value 0 (a == b)
    Pred = CmpInst::ICMP_EQ;
  else if (Bitmask == 3) // Values -1 or 0 (a <= b)
    Pred = CmpInst::getInversePredicate(cast<CmpIntrinsic>(II)->getGTPredicate());
  else if (Bitmask == 6) // Values 0 or 1 (a >= b)
    Pred = CmpInst::getInversePredicate(cast<CmpIntrinsic>(II)->getLTPredicate());
  else if (Bitmask == 5) // Values -1 or 1 (a != b)
    Pred = CmpInst::ICMP_NE;
  else
    return false;

  Value *Cond = Builder.CreateICmp(Pred, A, B, "cmp");
  return simplifyTerminatorOnSelect(SI, Cond, NonDefaultDest, DefaultDest, 0, 0);
'"}

